"# Read the file\n$lines = Get-Content 'app/me/page.tsx'\n\n# Process each line\n$newLines = @()\nforeach ($line in $lines) {\n    if ($line -match 'const profile: UserProfile = \{') {\n        $newLines += $line\n        $newLines += '    fullName: fullName || \"\",'\n    }\n    elseif ($line -match 'value=\{fullName') {\n        $newLines += $line -replace 'fullName', 'editDraft.fullName'\n    }\n    elseif ($line -match 'onChange=\{v => setStoreProfile') {\n        $newLines += $line -replace 'setStoreProfile\(\{ fullName: v \}\)', 'setDraft(d => ({ ...(d ?? profile), fullName: v }))'\n    }\n    elseif ($line -match 'display_name: fullName,') {\n        $newLines += $line -replace 'fullName', 'updated.fullName'\n    }\n    else {\n        $newLines += $line\n    }\n}\n\n# Write back\n$newLines | Set-Content 'app/me/page.tsx' -Encoding UTF8\nWrite-Host 'Bug fixed!'"